/* v64 - keep quick employee leave balance directly under work status */
(function(){
  if (window.__v64QuickLeaveUnderWorkStatus) return;
  window.__v64QuickLeaveUnderWorkStatus = true;
  function placeQuickLeaveBalance(){
    var modal = document.querySelector('#quickViewModal');
    var content = document.querySelector('#quickViewContent');
    if(!modal || !content) return;
    var card = content.querySelector('.leave-balance-profile-card');
    var status = content.querySelector('.employee-profile-side-status');
    if(card && status && card.previousElementSibling !== status){
      status.insertAdjacentElement('afterend', card);
    }
  }
  function scheduleQuickLeavePlacement(){
    placeQuickLeaveBalance();
    setTimeout(placeQuickLeaveBalance, 0);
    setTimeout(placeQuickLeaveBalance, 120);
    setTimeout(placeQuickLeaveBalance, 450);
  }
  document.addEventListener('click', function(e){
    if(e.target && e.target.closest && e.target.closest('.quick-view-btn, [data-quick-view], [data-view-employee]')){
      scheduleQuickLeavePlacement();
    }
  }, true);
  document.addEventListener('DOMContentLoaded', scheduleQuickLeavePlacement);
  try {
    var modal = document.querySelector('#quickViewModal');
    if(modal){
      new MutationObserver(scheduleQuickLeavePlacement).observe(modal, {attributes:true, childList:true, subtree:true});
    }
  } catch(e) {}
})();


