  function fmt(v){ try{return typeof formatDate==='function'?formatDate(v):(v||'—');}catch(_){return v||'—';} }
  function num(v){ try{return typeof arabicNumber==='function'?arabicNumber(v||0):String(v||0);}catch(_){return String(v||0);} }
